import Swal from 'sweetalert2'
import './App.css'; 

import React, { useState } from 'react';
import { render } from 'react-dom';
import withReactContent from 'sweetalert2-react-content'





  // customClass: {
  //   container: '...',
  //   popup: '...',
  //   header: '...',
  //   title: '...',
  //   closeButton: '...',
  //   icon: '...',
  //   image: '...',
  //   htmlContainer: '...',
  //   input: '...',
  //   inputLabel: '...',
  //   validationMessage: '...',
  //   actions: '...',
  //   confirmButton: '...',
  //   denyButton: '...',
  //   cancelButton: '...',
  //   loader: '...',
  //   footer: '....',
  //   timerProgressBar: '....',
  // }



  export const alertType = Object.freeze({
    InvalidInput: 'invalid',
    Success: 'success',
    NewFlyer: 'new_flyer',
  });


  export const FreeAlerts = (type) =>{
    console.log("Sweet Alert - type -" + type);
    switch(type){
      case 'invalid':
        inValidInputAlert();
        break;
      case 'success':
        successAlert();
        break;
      case 'new_flyer':
        newFlyerAlert()
        break;
      default:

        console.log("Sweet Alert - invalid option");
        break;
    }
  }

  const inValidInputAlert = () => {
    Swal.fire({  
      title: 'Did you enter the number properly?',  
      text: 'Please enter a valid phone number',
      icon: 'warning',
      showConfirmButton: false,
      timer: 2000,

      customClass:{
        title: 'sweet_title',
        // header: 'sweet_title',
        // container: 'sweet_title',
        // validationMessage: 'sweet_title',
        popup: 'sweet_container',

      }
    }); 
  }

  const successAlert = () => {
    Swal.fire({
      position: 'top-end',
      icon: 'success',
      title: 'Your log in completed',
      showConfirmButton: false,
      timer: 1500,
      customClass:{
        title: 'sweet_title',
        header: 'sweet_title',
        popup: 'sweet_container',
      }
    });
  }


 const newFlyerAlert = () => {

  const MySwal = withReactContent(Swal);

  let changePwSwal = {
    title: 'Change Password?',
    focusConfirm: false,
    html: `
      <input class="swal2-input" id="currentPassword" type="password" placeholder="Enter your current password..." /><br />
      <input class="swal2-input" id="newPassword1" type="password" placeholder="Enter your new password..." /><br />
      <input class="swal2-input" id="newPassword2" type="password" placeholder="Confirm your new password..." />
    `,
    type: 'warning',
    showCancelButton: true,
    cancelButtonColor: 'grey',
    confirmButtonText: 'Update!',
    allowOutsideClick: false,
    preConfirm: () => ({
      currentPassword: document.getElementById('currentPassword').value,
      newPassword1: document.getElementById('newPassword1').value,
      newPassword2: document.getElementById('newPassword2').value
    })
  };

  const swalval = MySwal.fire(changePwSwal).then((result) => {
            /* Read more about isConfirmed, isDenied below */
            if (result.isConfirmed) {

                Swal.fire('Nice to meet you', '', 'success');

            } else
                Swal.fire(' Cancelled', '', 'error')

        })


  let v = swalval && swalval.value || swalval.dismiss;




  }


